"use strict";parserFactory.register("novelspread.com",()=>new NovelSpreadParser),parserFactory.register("m.novelspread.com",()=>new MNovelSpreadParser);class NovelSpreadParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=[...e.querySelectorAll("div.volumeBox a")].map(e=>util.hyperLinkToChapter(e));for(let e=0;e<t.length;++e){let r=t[e];r.title=`${e+1}. ${r.title}`}return t}findContent(e){return Parser.findConstrutedContent(e)}extractTitleImpl(e){return e.title.split("-")[0]}extractAuthor(e){let t=e.querySelector("div.main-left div.person h4");return null===t?super.extractAuthor(e):t.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.novelimg")}async fetchChapter(e){let t=NovelSpreadParser.extractRestUrl(e),r=(await HttpClient.fetchJson(t)).json.data;return NovelSpreadParser.buildChapter(r)}static extractRestUrl(e){let t=new URL(e).pathname.split("/"),r=t.length-1;return`https://api.novelspread.com/api/novel/${t[r-1]}/chapter/${t[r].split("-")[1]}/content`}static buildChapter(e){let t="https://www.novelspread.com"+e.path,r=Parser.makeEmptyDocForContent(t),n=r.dom.createElement("h1");n.textContent=`${e.chapter_number}. ${e.chapter_title}`,r.content.appendChild(n);let l=util.sanitize(e.chapter_content);return util.moveChildElements(l.body,r.content),r.dom}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.info, div.syn")]}}class MNovelSpreadParser extends NovelSpreadParser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("a")].filter(e=>e.href.includes("/chapter/")).map(e=>util.hyperLinkToChapter(e))}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.book")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.synopsis div")]}}